#include <bits/stdc++.h>
using namespace std;

int N, M, V;
vector<int> adj[1001];
bool vis[1001];
vector<int> order;

void dfs(int cur) {
    vis[cur] = true;
    order.push_back(cur);
    for (int nx : adj[cur]) {
        if (!vis[nx]) dfs(nx);
    }
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> N >> M >> V;
    for (int i = 0; i < M; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    for (int i = 1; i <= N; i++) sort(adj[i].begin(), adj[i].end());

    dfs(V);
    for (int i = 0; i < (int)order.size(); i++) {
        cout << order[i];
        if (i + 1 < (int)order.size()) cout << ' ';
    }
    cout << "\n";

    fill(vis + 1, vis + N + 1, false);
    vector<int> border;
    queue<int> q;
    q.push(V); vis[V] = true;
    while (!q.empty()) {
        int cur = q.front(); q.pop();
        border.push_back(cur);
        for (int nx : adj[cur]) {
            if (!vis[nx]) { vis[nx] = true; q.push(nx); }
        }
    }
    for (int i = 0; i < (int)border.size(); i++) {
        cout << border[i];
        if (i + 1 < (int)border.size()) cout << ' ';
    }
    cout << "\n";
    return 0;
}
